    cin.tie(0);
#define endl '\n'
#define f first
#define s second

typedef unsigned long long llu;
typedef unsigned int ui;
typedef long long ll;

int valor_nota(char& nota)
{
    switch (nota)
    {
        case 'W':
            return 64;
        case 'H':
            return 32;
        case 'Q':
            return 16;
        case 'E':
            return 8;
        case 'S':
            return 4;
        case 'T':
            return 2;
        case 'X':
            return 1;
        default:
            return 0;
    }
}

int main()
{
    string entrada;
    const int completo = 64;
    int atual = 0;
    int compassos = 0;
    while (cin >> entrada)
    {
        if (entrada == "*")
            break;
        compassos = 0;
        atual = 0;
        for (char& c : entrada)
        {
            if (c == '/')
            {
                if (atual == completo)
                {
                    compassos++;
                }
                atual = 0;
            }
            else
            {
                atual += valor_nota(c);
            }
        }

        cout << compassos << endl;
    }

    return 0;
}